const app = express();

app.get("/whois", (req, res) => {
    const domain = req.query.domain;

    // Basic validation to ensure domain is provided
    if (!domain || typeof domain !== 'string') {
        return res.status(400).send("Invalid domain provided");
    }

    // execFile takes the command and an array of arguments, preventing shell injection
    execFile("whois", [domain], (err, stdout) => {
        if (err) return res.status(500).send("Error performing lookup");
        res.type("text/plain").send(stdout);
    });
});
