#include <cstdio>
#include <cstring>

class Buffer {
public:
    Buffer(size_t n) : data_(n) {}
    // Destructor, copy/move constructors are now handled automatically by std::vector

    char *raw() { return data_.data(); }
    size_t size() const { return data_.size(); }

private:
    std::vector<char> data_;
};

// Pass by reference to avoid unnecessary copying
void copy_and_log(const Buffer& src) {
    Buffer dst(src.size()); 
    std::memcpy(dst.raw(), "hello", 5);
    // Ensure null-termination before printing
    if (dst.size() > 5) dst.raw()[5] = '\0'; 
